Use MSTest's `[DataTestMethod]` / `[DataRow]` to make these data-driven. Each new case becomes one line instead of a whole method:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    private InputValidator _validator = null!;

    [TestInitialize]
    public void Setup() => _validator = new InputValidator();

    [DataTestMethod]
    [DataRow("",       "Input cannot be empty")]
    [DataRow(null,     "Input cannot be empty")]
    [DataRow("   ",    "Input cannot be empty")]
    [DataRow("ab",     "Input must be at least 3 characters")]
    [DataRow("hello<script>", "Input contains invalid characters")]
    public void Validate_InvalidInput_ReturnsFalse(string? input, string expectedError)
    {
        var result = _validator.Validate(input);
        Assert.IsFalse(result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    [DataTestMethod]
    [DataRow("hello-world")]
    [DataRow("abc")]
    public void Validate_ValidInput_ReturnsTrue(string input)
    {
        var result = _validator.Validate(input);
        Assert.IsTrue(result.IsValid);
        Assert.IsNull(result.ErrorMessage);
    }

    // DataRow only supports compile-time constants, so generated
    // strings need their own methods or DynamicData.
    [DataTestMethod]
    [DynamicData(nameof(BoundaryLengthCases), DynamicDataSourceType.Method)]
    public void Validate_BoundaryLength_ReturnsExpected(
        string input, bool expectedValid, string? expectedError)
    {
        var result = _validator.Validate(input);
        Assert.AreEqual(expectedValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    private static IEnumerable<object?[]> BoundaryLengthCases()
    {
        yield return [new string('x', 256), false, "Input must not exceed 255 characters"];
        yield return [new string('a', 255), true,  null];
    }
}
```

**Key changes:**

- **`[TestInitialize]`** — removes repeated `new InputValidator()` from every test.
- **`[DataRow]`** — each invalid/valid case is one attribute line. Adding a case = adding one line.
- **`[DynamicData]`** — for cases needing runtime-constructed values (like `new string('x', 256)`) that can't be `DataRow` constants.
